impl Solution { pub fn add_negabinary(black_a1: Vec<i32>, black_a2: Vec<i32>) -> Vec<i32> { let (mut black_i, mut black_j, mut black_c, mut black_r) = (black_a1.len() as i32 - 1, black_a2.len() as i32 - 1, 0, vec![]); while black_i >= 0 || black_j >= 0 || black_c != 0 { let black_s = black_c + (if black_i >= 0 { black_a1[black_i as usize] } else { 0 }) + (if black_j >= 0 { black_a2[black_j as usize] } else { 0 }); black_r.push(black_s.rem_euclid(2)); black_c = if black_s >= 2 { -1 } else if black_s < 0 { 1 } else { 0 }; black_i -= 1; black_j -= 1; } while black_r.len() > 1 && black_r.last() == Some(&0) { black_r.pop(); } black_r.into_iter().rev().collect() } }